  (function() {
    const data = get_TraCuu_PhieuXuat.data || [];

    if (data.length === 0) {
      return `
        <div style="font-family: -apple-system, sans-serif; display: flex; justify-content: center; align-items: center; height: 100vh; color: #64748b;">
          <h2>📭 Bảng tra cứu xuất kho đang trống... Vui lòng chọn điều kiện!</h2>
        </div>
      `;
    }

    let rowsHTML = data.map((item, index) => {
      let maPhieu = item['Mã Phiếu Xuất'] || '-';

      // Xử lý cắt bỏ giờ phút, chỉ lấy ngày
      let ngayXuat = item['Ngày Xuất'] ? item['Ngày Xuất'].split(' ')[0] : '-'; 

      let donViNhan = item['Đơn Vị Nhận'] || '-';
      let maDonHang = item['Mã Đơn Hàng'] || '-';
      let maBTP = item['Mã BTP'] || '-';

      let maVT = item['Mã Vật Tư'] || '';
      let tenVT = item['Tên Vật Tư'] || '';
      let vatTuFull = maVT ? `<strong>${maVT}</strong><br><span style="font-size: 11px; color: #475569;">${tenVT}</span>` : '-';

      let mauSac = item['Màu Sắc'] || '-';
      let soLuong = item['Số Lượng'] || 0;
      let dvt = item['ĐVT'] || '-';
      let lyDo = item['Lý Do Xuất'] || item['Lý Do'] || '-'; 
      let nguoiTao = item['Người Tạo'] || '-';
      let nguoiNhan = item['Người Nhận'] || '-';
      let ghiChu = item['Ghi Chú'] || '-';

      return `
        <tr>
          <td>${index + 1}</td>
          <td class="text-left" style="font-weight: bold; color: #0369a1;">${maPhieu}</td>
          <td>${ngayXuat}</td>
          <td class="text-left" style="font-weight: 500;">${donViNhan}</td>
          <td class="text-left font-semibold">${maDonHang}</td>
          <td class="text-left" style="color: #0f172a; font-weight: 500;">${maBTP}</td>
          <td class="text-left">${vatTuFull}</td>
          <td>${mauSac}</td>
          <td class="col-highlight text-red">${soLuong}</td>
          <td>${dvt}</td>
          <td class="text-left">${lyDo}</td>
          <td class="text-left" style="font-size: 11px;">
            <div style="margin-bottom: 3px;"><span style="color: #64748b;">Tạo:</span> <strong>${nguoiTao}</strong></div>
            <div><span style="color: #64748b;">Nhận:</span> ${nguoiNhan}</div>
          </td>
          <td class="text-left" style="font-size: 11px; color: #475569;">${ghiChu}</td>
        </tr>
      `;
    }).join('');

    return `
      <!DOCTYPE html>
      <html>
      <head>
        <style>
          body { margin: 0; padding: 0; background-color: #fff; }
          .erp-table-container { width: 100%; height: 100vh; overflow: auto; font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif; }

          /* ÉP CỐ ĐỊNH KÍCH THƯỚC CỘT VÀ TỰ ĐỘNG XUỐNG DÒNG */
          table { width: 100%; border-collapse: collapse; font-size: 12px; table-layout: fixed; min-width: 1300px; } 

          th { background-color: #f1f5f9; color: #0f172a; font-weight: bold; text-align: center; padding: 10px 4px; border: 1px solid #cbd5e1; position: sticky; top: 0; z-index: 10; word-wrap: break-word; box-shadow: 0 1px 0 #cbd5e1; }
          td { padding: 8px 4px; border: 1px solid #cbd5e1; color: #1e293b; vertical-align: middle; text-align: center; word-wrap: break-word; overflow-wrap: break-word; white-space: normal; }

          td.text-left { text-align: left; }
          .font-semibold { font-weight: 600; }
          .col-highlight { font-weight: bold; font-size: 14px; }
          .text-red { color: #dc2626; }
          tbody tr:hover { background-color: #f8fafc; }
        </style>
      </head>
      <body>
        <div class="erp-table-container">
          <table id="xuatKhoTable">
            <thead>
              <tr>
                <th style="width: 20px;">STT</th>
                <th style="width: 130px;">Mã Phiếu</th>
                <th style="width: 80px;">Ngày Xuất</th>
                <th style="width: 100px;">Đơn Vị Nhận</th>
                <th style="width: 80px;">Mã ĐH</th>
                <th style="width: 100px;">Mã BTP</th>
                <th style="width: 140px;">Vật Tư</th>
                <th style="width: 70px;">Màu Sắc</th>
                <th style="width: 70px;">Số Lượng</th>
                <th style="width: 45px;">ĐVT</th>
                <th style="width: 110px;">Lý Do Xuất</th>
                <th style="width: 130px;">Nhân Sự</th>
                <th style="width: 130px;">Ghi Chú</th>
              </tr>
            </thead>
            <tbody>
              ${rowsHTML}
            </tbody>
          </table>
        </div>
      </body>
      </html>
    `;
  })()
}}
